<?php
namespace App\Domain\Inventory;
use App\Domain\Equipment\CharacterEquipmentSlot;use App\Domain\Equipment\EquipmentEligibilityService;use App\Domain\Equipment\EquipmentLoadoutValidator;use App\Domain\Equipment\EquippableItemValidator;use App\Domain\Inventory\Capacity\InventorySlotCalculator;use App\Domain\Inventory\Capacity\PendingRewardCapacityService;use App\Domain\Inventory\Instances\Data\ItemInstanceEntry;use App\Domain\Inventory\Instances\ItemInstanceInventoryPolicy;use App\Models\Character;use App\Models\CharacterEquipment;use App\Models\Item;use App\Models\ItemInstance;use Carbon\CarbonImmutable;use InvalidArgumentException;
final class CharacterInventorySummaryService{private $inventory;private $slots;private $capacity;private $classification;private $instancePolicy;private $equippable;private $eligibility;private $loadouts;private $stackExpander;public function __construct(InventoryService $inventory,InventorySlotCalculator $slots,PendingRewardCapacityService $capacity,ItemClassification $classification,ItemInstanceInventoryPolicy $instancePolicy,EquippableItemValidator $equippable,EquipmentEligibilityService $eligibility,EquipmentLoadoutValidator $loadouts,InventoryStackExpander $stackExpander){$this->inventory=$inventory;$this->slots=$slots;$this->capacity=$capacity;$this->classification=$classification;$this->instancePolicy=$instancePolicy;$this->equippable=$equippable;$this->eligibility=$eligibility;$this->loadouts=$loadouts;$this->stackExpander=$stackExpander;}
 public function snapshot(Character $character,CarbonImmutable $now=null){$character->loadMissing('characterClass');$entries=$this->inventory->entries($character);$ids=$entries->map(function($entry){return$entry->itemId();})->unique()->values();$items=$ids->isEmpty()?collect():Item::whereIn('id',$ids)->get()->keyBy('id');$rows=[];foreach($entries as $entry){$item=$items->get($entry->itemId());if(!$item||$this->classification->classify($item)!==ItemClassification::STACKABLE||(int)$entry->totalQuantity()<=0)throw new InvalidArgumentException('Invalid stackable inventory summary state.');$used=$this->slots->calculate([['item_id'=>(int)$item->id,'quantity'=>(int)$entry->totalQuantity(),'max_stack'=>(int)$item->max_stack]])->slots();$stackQuantities=$this->stackExpander->expand((int)$entry->totalQuantity(),(int)$item->max_stack);if(count($stackQuantities)!==$used)throw new InvalidArgumentException('Inventory stack presentation does not match occupied slots.');$rows[]=['item_id'=>(int)$item->id,'item_code'=>$item->code,'item_name'=>$item->name,'quantity'=>(int)$entry->totalQuantity(),'locked_quantity'=>(int)$entry->lockedQuantity(),'available_quantity'=>(int)$entry->availableQuantity(),'max_stack'=>(int)$item->max_stack,'used_slots'=>$used,'stack_quantities'=>$stackQuantities];}usort($rows,function($a,$b){$name=strcmp($a['item_name'],$b['item_name']);return$name!==0?$name:$a['item_id']<=>$b['item_id'];});
$allInstances=ItemInstance::where('character_id',$character->id)->with(['item.allowedCharacterClasses'])->orderBy('id')->get();$equipment=CharacterEquipment::where('character_id',$character->id)->orderBy('id')->get();$catalog=$allInstances->pluck('item')->filter()->keyBy('id');$instances=$allInstances->filter(function($instance){return$this->instancePolicy->occupiesInventory($instance->status);})->map(function($instance)use($character,$allInstances,$equipment,$catalog){$item=$instance->item;if(!$item||$this->classification->classify($item)!==ItemClassification::UNIQUE)throw new InvalidArgumentException('Invalid ItemInstance summary state.');$type=$this->equippable->equipmentType($item);$slots=$type===null?[]:CharacterEquipmentSlot::slotsForType($type);$eligibility=[];foreach($slots as $slot){$individual=$this->eligibility->evaluate($character,$instance,$item,$slot,$item->allowedCharacterClasses,$character->characterClass)->toArray();if($individual['eligible']){$loadout=$this->loadouts->evaluate($slot,$item,$equipment,$allInstances,$catalog,$character->characterClass)->toArray();$individual['eligible']=$loadout['allowed']||$loadout['requires_confirmation'];$individual['message']=$loadout['reason']?:$individual['message'];$individual['loadout']=$loadout;}else$individual['loadout']=null;$eligibility[$slot]=$individual;}return array_merge((new ItemInstanceEntry($instance->uuid,(int)$item->id,$item->code,$item->name,(int)$instance->refinement_level,$instance->status,$instance->acquired_at->toIso8601String()))->toArray(),['equipment_type'=>$type,'compatible_slots'=>$slots,'required_level'=>(int)$item->required_level,'eligibility_by_slot'=>$eligibility,'bonuses'=>$this->equippable->bonuses($item)->toArray()]);})->values()->all();
$capacity=$this->capacity->snapshot($character,$now?:CarbonImmutable::now())->toArray();return['stackable_items'=>$rows,'item_instances'=>$instances,'inventory_status'=>['effective_capacity'=>$capacity['effective_capacity'],'current_used_slots'=>$capacity['current_used_slots'],'current_free_slots'=>$capacity['current_free_slots']],'pending_projection'=>['projected_used_slots'=>$capacity['projected_used_slots'],'projected_free_slots'=>$capacity['projected_free_slots'],'claim_fits'=>$capacity['claim_fits'],'missing_slots_for_claim'=>$capacity['missing_slots_for_claim'],'effective_reserve'=>$capacity['effective_reserve'],'hunting_can_continue'=>$capacity['hunting_can_continue']]];}}
